import React, { useEffect, useRef, useState } from 'react';
import { Mail, Camera, Clock, Calendar } from 'lucide-react';

const playlist = [
  '/audio/song1.mp3',
  '/audio/song2.mp3',
  '/audio/song3.mp3',
];

const HomePage: React.FC = () => {
  const audioRef = useRef<HTMLAudioElement>(null);
  const [playing, setPlaying] = useState(false);
  const [visible, setVisible] = useState(false);
  const [currentTrack, setCurrentTrack] = useState(0);

  useEffect(() => {
    setTimeout(() => setVisible(true), 200);
  }, []);

  // 🔥 ONE CLICK → change song + play
  const toggleAudio = () => {
    if (!audioRef.current) return;

    const nextTrack = (currentTrack + 1) % playlist.length;
    setCurrentTrack(nextTrack);

    setTimeout(() => {
      audioRef.current?.play().catch(() => {});
      setPlaying(true);
    }, 120);
  };

  const scrollTo = (id: string) => {
    document.getElementById(id)?.scrollIntoView({ behavior: 'smooth' });
  };

  const FloatingPetal = ({ style }: { style: React.CSSProperties }) => (
    <div style={{
      position: 'absolute',
      fontSize: 18,
      animation: 'petalFall 8s linear infinite',
      pointerEvents: 'none',
      ...style,
    }}>🌸</div>
  );

  return (
    <section id="home" style={{
      minHeight: '100vh',
      background: 'linear-gradient(160deg, #1a0500 0%, #3d0c02 25%, #5c1204 50%, #3d0c02 75%, #1a0500 100%)',
      display: 'flex', flexDirection: 'column',
      alignItems: 'center', justifyContent: 'center',
      position: 'relative', overflow: 'hidden',
      padding: '60px 20px',
    }}>

      {/* 🔊 Audio (playlist based) */}
      <audio ref={audioRef} src={playlist[currentTrack]} preload="auto" />

      {/* Floating petals */}
      {[...Array(12)].map((_, i) => (
        <FloatingPetal key={i} style={{
          left: `${(i * 8.3) % 100}%`,
          top: `-5%`,
          animationDelay: `${i * 0.7}s`,
          animationDuration: `${6 + (i % 4)}s`,
          fontSize: 14 + (i % 3) * 6,
          opacity: 0.6,
        }} />
      ))}

      {/* === EVERYTHING BELOW IS UNCHANGED UI === */}

      {/* Big decorative rangoli SVG background */}
      <div style={{ position: 'absolute', opacity: 0.06, pointerEvents: 'none' }}>
        <svg width="600" height="600" viewBox="0 0 600 600">
          {[...Array(12)].map((_, i) => {
            const angle = (i / 12) * Math.PI * 2;
            const x = 300 + Math.cos(angle) * 220;
            const y = 300 + Math.sin(angle) * 220;
            return (
              <g key={i}>
                <line x1="300" y1="300" x2={x} y2={y} stroke="#FFD700" strokeWidth="1.5" />
                <circle cx={x} cy={y} r="12" fill="none" stroke="#FFD700" strokeWidth="2" />
                <circle cx={x} cy={y} r="5" fill="#FFD700" />
                <circle cx={300 + Math.cos(angle) * 140} cy={300 + Math.sin(angle) * 140} r="8" fill="#FF6B35" />
              </g>
            );
          })}
          {[80, 140, 200, 260].map(r => (
            <circle key={r} cx="300" cy="300" r={r} fill="none" stroke="#FFD700" strokeWidth="1" />
          ))}
          <circle cx="300" cy="300" r="25" fill="none" stroke="#FFD700" strokeWidth="3" />
          <circle cx="300" cy="300" r="8" fill="#FFD700" />
        </svg>
      </div>

      {/* Audio control button (UNCHANGED UI) */}
      <button
        onClick={toggleAudio}
        title="Change Song"
        style={{
          position: 'fixed',
          bottom: 28, right: 28,
          width: 52, height: 52,
          borderRadius: '50%',
          background: 'linear-gradient(135deg, #8B0000, #cc2200)',
          border: '2px solid rgba(255,215,0,0.6)',
          color: '#FFD700',
          fontSize: 20,
          cursor: 'pointer',
          zIndex: 100,
          boxShadow: playing
            ? '0 0 0 8px rgba(255,107,53,0.15), 0 4px 20px rgba(0,0,0,0.5)'
            : '0 4px 20px rgba(0,0,0,0.5)',
          transition: 'all 0.3s ease',
          animation: playing ? 'musicPulse 2s ease-in-out infinite' : 'none',
          display: 'flex', alignItems: 'center', justifyContent: 'center',
        }}
      >
        🎶
      </button>

      <style>{`
        @keyframes petalFall {
          0% { transform: translateY(-20px) rotate(0deg); opacity: 0; }
          10% { opacity: 0.6; }
          90% { opacity: 0.6; }
          100% { transform: translateY(110vh) rotate(720deg); opacity: 0; }
        }
        @keyframes musicPulse {
          0%, 100% { box-shadow: 0 0 0 0 rgba(255,107,53,0.4); }
          50% { box-shadow: 0 0 0 12px rgba(255,107,53,0); }
        }
      `}</style>
    </section>
  );
};

export default HomePage;
